          <span>{{ batteryText }}</span>
        </div>
      </div>
    </div>

    <!-- 状态图例 -->
    <div class="status-legend">
      <div
        class="legend-item"
        v-for="(status, key) in STATUS_CONFIG"
        :key="key"
      >
        <div
          class="status-indicator"
          :style="{ backgroundColor: status.color }"
        ></div>
        <span>{{ status.label }}</span>
      </div>
    </div>

    <div class="bottom flex-space-between">
      <div class="box flex-direction-column">
        <!-- 使用统一的模板渲染每个设备组 -->
        <!-- 模板部分 -->
        <template v-for="group in leftGroups" :key="group.title">
          <div class="item flex">
            <div class="aside">{{ group.title }}</div>
            <div class="status flex-direction-column">
              <div
                class="s-item flex"
                v-for="item in group.items"
                :key="item.id"
              >
                <div
                  class="status-indicator"
                  :style="{
                    backgroundColor: getDeviceStatus(item.type, item.id)
                  }"
                ></div>
                <span>{{ item.label }}</span>
              </div>
            </div>
          </div>
        </template>
      </div>

      <div class="pic">
        <img src="@/assets/img/tianyi-prod-2.0.png" alt="" />
      </div>

      <div class="box flex-direction-column">
        <!-- 模板部分 -->
        <template v-for="group in rightGroups" :key="group.title">
          <div class="item flex">
            <div class="aside">{{ group.title }}</div>
            <div class="status flex-direction-column">
              <div
                class="s-item flex"
                v-for="item in group.items"
                :key="item.id"
              >
                <div
                  class="status-indicator"
                  :style="{
                    backgroundColor: getDeviceStatus(item.type, item.id)
                  }"
                ></div>
                <span>{{ item.label }}</span>
              </div>
            </div>
          </div>
        </template>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import proto from '@/utils/sdkapi_pb.js'

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)

import { STATUS_CONFIG } from '@/constants/status'
import { useStatus } from '@/hooks/useStatus'
const { getStatusColor } = useStatus()

// 监听连接状态
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      // 当连接成功时发送命令13
      const request = new proto.Request()
      request.setCommand(proto.Command.CMD_GET_STATUS_DATA)
      const data = request.serializeBinary()
      store.websocketSendData({ data })
    }
  },
  { immediate: true } // 立即执行一次
)

// 左侧设备组配置
const leftGroups = [
  {
    title: '头部',
    items: [
      { id: '', type: 'head', label: '头部相机' },
      { id: '', type: 'head', label: '扬声器' },
      { id: '', type: 'head', label: '麦克风' }
    ]
  },
  {
    title: '右肩',
    items: [
      { id: '11', type: 'motor', label: '右肩关节俯仰' },
      { id: '12', type: 'motor', label: '右肩关节侧展' },
      { id: '13', type: 'motor', label: '右肩关节周转' },
      { id: '14', type: 'motor', label: '右肘关节侧展' },
      { id: '15', type: 'motor', label: '右腕关节周转' },
      { id: '16', type: 'motor', label: '右腕关节俯仰' },
      { id: '17', type: 'motor', label: '右腕关节侧展' }
    ]
  },
  {
    title: '手部',
    items: [
      { id: '41', type: '6dof', label: '右六维力' },
      { id: '42', type: 'hand', label: '右手' },
      { id: '43', type: '6dof', label: '左六维力' },
      { id: '44', type: 'hand', label: '左手' }
    ]
  },
  {
    title: '电源板',
    items: [
      { id: '', type: 'power', label: '电源' },
      { id: '', type: 'switch', label: '急停开关' }
    ]
  }
]

// 右侧设备组配置
const rightGroups = [
  {
    title: '颈部',
    items: [
      { id: '1', type: 'motor', label: '头关节周转' },
      { id: '2', type: 'motor', label: '头关节俯仰' },
      { id: '3', type: 'motor', label: '头关节侧展' }
    ]
  },
  {
    title: '左肩',
    items: [
      { id: '21', type: 'motor', label: '左肩关节俯仰' },
      { id: '22', type: 'motor', label: '左肩关节侧展' },
      { id: '23', type: 'motor', label: '左肩关节周转' },
      { id: '24', type: 'motor', label: '左肘关节侧展' },
      { id: '25', type: 'motor', label: '左腕关节周转' },
      { id: '26', type: 'motor', label: '左腕关节俯仰' },
      { id: '27', type: 'motor', label: '左腕关节侧展' }
    ]
  },
  {
    title: '下肢',
    items: [
      { id: '31', type: 'motor', label: '腰关节周转' },
      { id: '32', type: 'motor', label: '腰关节俯仰' },
      { id: '51', type: 'motor', label: '髋关节俯仰' },
      { id: '52', type: 'motor', label: '膝关节俯仰' }
    ]
  },
  {
    title: '底盘',
    items: [
      { id: '', type: 'chassis', label: '底盘' },
      { id: '', type: 'remote', label: '遥控' }
    ]
  }
]

// 统一的状态获取函数
const getDeviceStatus = (type, id = null) => {
  const statusData = received.value?.statusData

  switch (type) {
    // case 'head':
    //   //待写
    //   return getStatusColor('unknown')

    case 'power':
      return getStatusColor(statusData?.powerDataList?.[0]?.status)

    case 'switch':
      return getStatusColor(statusData?.switchDataList?.[0]?.status)

    case 'chassis':
      return getStatusColor(statusData?.chassisDataList?.[0]?.status)

    case 'motor': {
      const motorData = statusData?.motorDataList?.find(
        (m) => m.devid.toString() === id.toString()
      )
      return getStatusColor(motorData?.status)
    }

    case 'hand': {
      const handData = statusData?.handDataList?.find(
        (m) => m.devid.toString() === id.toString()
      )
      return getStatusColor(handData?.status)
    }

    case '6dof': {
      const sixDofData = statusData?.sixDofDataList?.find(
        (m) => m.devid.toString() === id.toString()
      )
      return getStatusColor(sixDofData?.status)
    }

    case 'remote':
      return getStatusColor(statusData?.remoteControlDataList?.[0]?.status)

    default:
      return getStatusColor('unknown')
  }
}

const batteryPercentage = computed(() => {
  const batteryLevel =
    received.value?.statusData?.powerDataList?.[0]?.batteryLevel
  return batteryLevel !== undefined && batteryLevel !== null
    ? Number(batteryLevel).toFixed(2) // 保留两位小数，确保转换为数字
    : null
})

const batteryColor = computed(() => {
  if (batteryPercentage.value === null) return '#B0B0B0'
  return batteryPercentage.value > 20 ? '#27FF23' : '#FF0000'
})

const batteryLevelStyle = computed(() => ({
  width:
    batteryPercentage.value === null ? '100%' : `${batteryPercentage.value}%`,
  backgroundColor: batteryColor.value
}))

const batteryText = computed(() =>
  batteryPercentage.value === null ? '？%' : `${batteryPercentage.value}%`
)
</script>

